"use client";

import Link from "next/link";
import { usePathname } from "next/navigation";
import { useAuth } from "@/context/AuthContext";
import styles from "./Layout.module.css";

const menuItems = [
    { name: "Overview", href: "/dashboard", icon: "📊" },
    { name: "My Approvals", href: "/dashboard/approvals", icon: "✅" },
    { name: "Requisitions", href: "/dashboard/requisitions", icon: "📝" },
    { name: "Purchase Orders", href: "/dashboard/purchase-orders", icon: "📦" },
    { name: "Invoices", href: "/dashboard/invoices", icon: "🧾" },
    { name: "Vendors", href: "/dashboard/vendors", icon: "🏢" },
    { name: "Budgets", href: "/dashboard/budgets", icon: "💰" },
    { name: "Analytics", href: "/dashboard/analytics", icon: "📈" },
];

export default function Sidebar() {
    const pathname = usePathname();
    const { user } = useAuth();

    return (
        <aside className={styles.sidebar}>
            <div className={styles.logoContainer}>
                <div className={styles.logoIcon}>Pv</div>
                <div className={styles.logoText}>Procurify</div>
            </div>

            <div className={styles.sectionTitle}>Main Menu</div>
            <nav style={{ flex: 1, overflowY: 'auto' }}>
                <ul style={{ listStyle: 'none' }}>
                    {menuItems.map((item) => {
                        const isActive = pathname === item.href;
                        return (
                            <li key={item.name}>
                                <Link
                                    href={item.href}
                                    className={`${styles.navLink} ${isActive ? styles.navLinkActive : ''}`}
                                >
                                    <span className={styles.navIcon}>{item.icon}</span>
                                    {item.name}
                                </Link>
                            </li>
                        );
                    })}
                    {user?.role === 'ADMIN' && (
                        <li>
                            <Link
                                href="/dashboard/support"
                                className={`${styles.navLink} ${pathname === '/dashboard/support' ? styles.navLinkActive : ''}`}
                            >
                                <span className={styles.navIcon}>🎧</span>
                                Support Tickets
                            </Link>
                        </li>
                    )}
                </ul>
            </nav>

            <div className={styles.bottomSection}>
                <div className={styles.userProfile}>
                    <div className={styles.userAvatar}>
                        {user?.displayName?.[0] || 'U'}
                    </div>
                    <div className={styles.userInfo}>
                        <div className={styles.userName}>{user?.displayName || 'User'}</div>
                        <div className={styles.userRole}>{user?.role || 'User'}</div>
                    </div>
                </div>
            </div>
        </aside>
    );
}
